using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=2e5+5;
int n,m;
string s;
int a[MAXN];
struct node
{
	int val,lz,l,r;
}t[MAXN<<2];
void pushup(int p)
{
	t[p].val=t[p<<1].val+t[p<<1|1].val;
}
void pushdown(int p)
{
	if(t[p].lz)
    {
		t[p<<1].val=(t[p<<1].r-t[p<<1].l+1)-t[p<<1].val;
		t[p<<1].lz^=t[p].lz;
		t[p<<1|1].val=(t[p<<1|1].r-t[p<<1|1].l+1)-t[p<<1|1].val;
		t[p<<1|1].lz^=t[p].lz;
		t[p].lz=0;
	}
}

void build(int p,int l,int r)
{
	t[p]={0,0,l,r};
	if(l==r)
    {
		t[p].val=a[l];
		return;
	}
	build(p<<1,l,mid);
	build(p<<1|1,mid+1,r);
	pushup(p);
}
void update(int p,int l,int r)
{
	if(t[p].l>=l&&t[p].r<=r)
    {
		t[p].val=(t[p].r-t[p].l+1)-t[p].val;
		t[p].lz^=1;
		return;
	}
	pushdown(p);
	if(t[p<<1].r>=l) update(p<<1,l,r);
	if(t[p<<1|1].l<=r) update(p<<1|1,l,r);
	pushup(p);
}
int query(int p,int l,int r)
{
	if(t[p].l>=l&&t[p].r<=r)
    {
		return t[p].val;
	}
	pushdown(p);
	int res=0;
	if(t[p<<1].r>=l) res+=query(p<<1,l,r);
	if(t[p<<1|1].l<=r) res+=query(p<<1|1,l,r);
	return res;
}
signed main(void)
{
	cin>>n>>m;
	cin>>s;
	for(int i=0;i<s.size();i++)
    {
		a[i+1]=s[i]-'0';
	}
	build(1,1,n);
	while(m--){
		int op,l,r;
		cin>>op>>l>>r;
		if(op==0)
        {
			update(1,l,r);
		}
		else
        {
			cout<<query(1,l,r)<<'\n';
		}
	}
	return false;
}
